var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"아르카데나 제국. 왕성.","JPN":"アルカデナ帝国。王城。","ENG":"Royal Palace, The Empire of Arcadena.","TWN":"艾爾卡特納帝國 皇宮"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"구원기사단. <color=#ffd34c>기사단 회의</color> 현장.","JPN":"救世騎士団。<color=#ffd34c>騎士団会議</color>の場。","ENG":"Knights of Redemption. <color=#ffd34c>Knights Council Assembly</color>.","TWN":"救贖騎士團 <color=#ffd34c>騎士團會議</color>現場"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"북부 대륙에서 이룬 성과는 이상입니다. 전하.","JPN":"北部の大陸で成し遂げた成果は以上です。殿下。","ENG":"And that is what we've achieved in the northern continent, Your Highness.","TWN":"以上為北方大陸取得的成果，殿下。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L7_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"조금 이른 감은 있지만 승기가 기운 듯합니다. ","JPN":"少し早くはありますが、勝機を掴んだのではないかと。","ENG":"It may be a little bit early, but it seems that we are in a favorable position.","TWN":"雖然要下定論還有點早，但似乎是十拿九穩。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"적군의 기세가 잦아들었으니, 당분간은 여유가 있을 것 같군요.","JPN":"敵軍の勢いが弱まりましたので、しばらくは余裕がありそうです。","ENG":"We should be able to rest easy for a while, as the enemies have lost their spirits.","TWN":"趁現在敵軍士氣潰散，我們應該可以暫時喘口氣。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"과연 알렌 경이야. 제국 기사단장직에 어울리는 나무랄 데 없는 지휘였네.","JPN":"さすがはバーミンガム卿。帝国の騎士団長に相応しい、申し分のない指揮だった。","ENG":"Well done, Sir Allen. An impeccable display of commanding skills that fits the position of the Empire's Knight Captain.","TWN":"不愧是艾倫卿，名符其實的帝國騎士團團長，調兵遣將高手。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"과찬이시군요. 아군 쪽 피해까지 고려한다면 완승이라고 볼 수는 없습니다.","JPN":"身に余るお言葉です。味方の被害まで考えると、圧勝とは言えません。","ENG":"I am not worthy of that praise. We have not achieved a complete victory, considering the amount of damage that we suffered.","TWN":"殿下過譽了，考慮到我方受到的損失，這場仗不能算是大獲全勝。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>몬테</color>의 건이나, 아직 해결해야 할 문제는 많습니다.","JPN":"<color=#ffd34c>モンテ</color>の件など、まだ解決すべき問題は多く残っています。","ENG":"There are plenty of remaining issues, including the one in <color=#ffd34c>Monte</color>.","TWN":"無論是<color=#ffd34c>蒙特</color>的事，或是其他尚有許多待解決的問題。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"나무를 보지 못하는데 어찌 숲을 볼 수 있겠나. 당장은 눈앞의 승리에 기뻐하도록 하지.","JPN":"木を見て森を見ずとは言うが、時には小さなことに気を配ることも必要か。","ENG":"How does one see the forest if one cannot see the trees?","TWN":"若無法享受當下的甜美果實，又怎麼會期待之後的豐收呢？應該享受在當下的勝利才對。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"마르티네즈 공. 서쪽 변방의 전황은 어떤가?","JPN":"マルチネス卿。西の辺境の戦況はどうだ？","ENG":"Marquise Martinez. What is the outlook on the western border areas?","TWN":"馬汀尼茲侯爵，西方邊境的戰況如何？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"명령하신 대로 반란군 간부를 매수했습니다.","JPN":"ご命令のとおり、反乱軍の幹部を買収しました。","ENG":"We bribed an officer in the rebel forces, as per your order.","TWN":"已經照殿下的吩咐，收買了叛軍的幹部。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"애초 권력욕에 휩싸여 뭉친 오합지졸들이었으니, 군세가 와해되는 건 시간문제일 겁니다.","JPN":"そもそも権力欲に溺れて集まった烏合の衆なので、軍勢が崩れるのは時間の問題でしょう。","ENG":"They were a disorderly group of power-hungry fools, so it is only a matter of time before their troops fall apart.","TWN":"他們不過是一群權欲薰心的烏合之眾，勢力瓦解是遲早的事。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"제 쪽도 별다른 이상은 없었습니다. 전하.","JPN":"僕の方も別に異常はありませんでした。殿下。","ENG":"There was nothing special on my side either, Your Highness.","TWN":"我這裡也沒什麼異狀，殿下。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"잇따른 승전보가 기운을 북돋아 준 것 같아요. 이전보다 사람들의 표정이 많이 좋아졌어요.","JPN":"勝利の知らせが続いたのが彼らを元気づけたようです。以前より人々の表情がだいぶ明るくなりました。","ENG":"The continued news of victory must have lifted the people's spirits. They look a lot brighter than before.","TWN":"接二連三的捷報，也使得民心大振，百姓的臉上都恢復了笑容。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"루크레시아 쪽은 어때?","JPN":"ルクレシアの方はどう？","ENG":"What about you, Lucrecia?","TWN":"露可蕾西亞那邊呢？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"루크레시아?","JPN":"ルクレシア？","ENG":"Lucrecia?","TWN":"露可蕾西亞？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"제 쪽도 별다른 문제는 없었습니다.","JPN":"私の方も、特に問題はありませんでした。","ENG":"I have nothing special to report either, Your Highness.","TWN":"我這邊也沒什麼特殊狀況。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"회의에 집중하지 못하는 건 괘씸하다만. 성녀는 그런 얼굴로 잘도 거짓말을 하는군.","JPN":"会議に集中できないのもけしからんが。そのような顔をしておきながらよくも嘘がつけたものだ、聖女よ。","ENG":"How deplorable of you to be distracted during the council assembly. Are you aware that your face tells a different story?","TWN":"我最討厭有人開會不認真，而且你的表情就寫著有事。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"고하라, 루크레시아. 마을 쪽에 무언가 이상이 있었던 건가?","JPN":"言え、ルクレシア。巡回中、異常でもあったか？","ENG":"Speak, Lucrecia. Was there a problem in the village?","TWN":"說吧，露可蕾西亞，村子那邊是發生什麼事嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그건...","JPN":"それは……","ENG":"Well...","TWN":"那個…"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_C","text":{"KOREA":"무도회에서 춤을 춘 남녀는 부부가 된다는 징크스가 있대요!","JPN":"舞踏会で一緒に踊った男女は、夫婦になるっていう噂があるらしいですよ！","ENG":"I heard that whoever dances together at the ball will later become husband and wife!","TWN":"聽說有個魔咒，就是在舞會上共舞的男女會成為夫妻！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_C","text":{"KOREA":"저도 이번에 좋아하는 애한테 용기내서 권유해보려고요.","JPN":"私も今度勇気を出して、好きな子を誘ってみるつもりです。","ENG":"I'm going to muster up some courage to ask my crush.","TWN":"所以我這次要找喜歡的男生跳舞。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_C","text":{"KOREA":"성녀님은 어떻게 하실 건가요?","JPN":"聖女様はどうしますか？","ENG":"What about you, Your Holiness?","TWN":"聖女呢？你打算邀請誰？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"사실, 굳이 말씀드릴 필요도 없는 사소한 일이 있긴 했습니다.","JPN":"実は、あえてお話しするまでもない些細なことが、あるにはありました。","ENG":"There was actually something minor that happened, not really worth mentioning.","TWN":"只是些微不足道的小事而已。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L45_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그래. 무엇이지?","JPN":"そうか。何だ？","ENG":"Right. Pray tell.","TWN":"是什麼事？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"도시에서 저희를 흉내 내며 기사단 놀이를 하는 아이들이 있었습니다.","JPN":"街で私たちのことを真似て騎士団ごっこをする子どもたちがいました。","ENG":"I saw some children who played knights and roleplayed as us in the city.","TWN":"城裡有些孩子會模仿我們，玩騎士團遊戲。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"전하가 구원자님께 깨지는 장면이 퍽이나 우습더군요.","JPN":"殿下が救世主様にやられるシーンが、とても面白かったです。","ENG":"It was very funny to see you get beat up by the Savior.","TWN":"殿下被救贖者大人大人壓著打的場景非常有趣。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하하! 그럼 성녀 역할을 하는 아이는 누구처럼 노출증 심한 옷이라도 입고 있던가?","JPN":"ハハ！　では、聖女の役割をしていた子どもは、誰かさんのように露出癖がうかがえる服でも着ていたか？","ENG":"Ha ha! Then did the child playing the Saintess wear something excessively revealing like a certain someone?","TWN":"哈哈！那模仿聖女的孩子也有穿著極度暴露的衣服嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_01"},{"id":"L49_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"제국의 질서가 많이 흐트러졌군. 당분간 영애들의 옷차림에 주의를 줘야겠어.","JPN":"帝国の秩序が相当乱れているな。しばらくは令嬢の服装に注意するよう命じよう。","ENG":"The Empire has become unruly. The young ladies must be taught how to dress properly.","TWN":"看來最近帝國的秩序堪憂，這段時間必須好好留意孩子們的穿著。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"노, 노출증이라뇨!","JPN":"ろ、露出癖だなんて！","ENG":"E-excessively revealing?!","TWN":"誰極度暴露！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L2_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"언동에 주의하십시오, 루크레시아. 성녀라고 한들 전하에 대한 무례는 용납할 수 없습니다.","JPN":"言動に注意されよ、ルクレシア。聖女とはいえ、殿下への無礼は許されません。","ENG":"Watch your tone, Lucrecia. Your position as Saintess does not excuse any rude behavior toward His Highness.","TWN":"請慎言，露可蕾西亞。就算你是聖女，我也不允許你對殿下無理。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L4_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"놔둬라. 천박한 고양이가 부뚜막에 오르는 일이 어디 한 둘이었나.","JPN":"放っておけ。聖女とは思えないような言動は今に始まったことではなかろう。","ENG":"It is fine. It's always the quiet ones. Or, I guess the obscene ones, in this case.","TWN":"隨她吧，路邊的野貓哪懂得什麼禮貌呢？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"별일은 아닌 듯싶으니 다음 안으로 넘어가도록 하지.","JPN":"これといった問題はなさそうだ、次の案件に移ろう。","ENG":"It does not seem to require my attention, so we shall move on.","TWN":"我想應該是沒什麼大事，會議就繼續往下走吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"알렌 경. 준비하라 했던 건 어떻게 되어가고 있나?","JPN":"バーミンガム卿。準備を命じた件はどうなっている？","ENG":"Sir Allen. What happened to the matter I told you to prepare?","TWN":"艾倫卿，我吩咐你的事準備得如何？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"승전 기념 연회라면 차질 없이 진행되고 있습니다.","JPN":"祝勝記念の宴の件でしたら、支障なく進められております。","ENG":"The victory banquet is being prepared according to plan.","TWN":"殿下是說慶功宴嗎？慶功宴正在預備中。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"다만 병사들 사이에서 아쉬운 목소리도 나오더군요.","JPN":"ただ、兵士の間では残念という声も上がっています。","ENG":"However, I heard some disappointed voices among the soldiers.","TWN":"只是士兵之中有人覺得有些遺憾。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"어째서? 저번에는 다들 즐거워 했잖아?","JPN":"どうして？　この前はみんな喜んでたでしょう？","ENG":"Why? I thought everyone loved it last time.","TWN":"怎麼會？上次大家不是都很開心嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"아르카데나 제국은 매년 이 시기에 왕가의 안녕을 위한 무도회를 개최했어.","JPN":"アルカデナ帝国は、毎年この時期に王家の安寧を祈る舞踏会を開催していた。","ENG":"Every year around this time, the Empire of Arcadena hosts a ball to wish for the peace and stability of the royal family.","TWN":"艾爾卡特納帝國每年這個時候都會舉辦為皇室祈福的舞會。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"제국의 축제 중 손꼽히는 규모였으니, 다들 무도회를 넘어가는데 아쉬운 마음이 클 거야.","JPN":"帝国の祭りの中でも指折りの規模であったから、皆、舞踏会を行わないことをとても残念がるはずだ。","ENG":"It is one of the biggest events in the Empire, so the masses must be disappointed to skip the ball.","TWN":"而且規模是帝國慶典中數一數二的，大家應該會覺得跳過舞會很可惜吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"확실히 알렌의 춤을 보지 못한다는 사실은 실로 유감이군.","JPN":"確かに、アレンのダンスを見られないというのは実に残念だな。","ENG":"It is such a shame not to be able to see Allen's dancing.","TWN":"確實，沒能看到艾倫的舞姿是蠻可惜的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그레이스와 추는 플라멩코는 제국 내에서도 명성이 자자한데 말이지.","JPN":"グレースと踊るフラメンコは、帝国内でも一見の価値ありとの評判だ。","ENG":"His flamenco with Grace is well known throughout the Empire.","TWN":"你和葛瑞絲跳的佛朗明哥舞，在帝國中可是赫赫有名呢。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"봐주시죠. 그건 춤이라기보단 폭력에 가깝습니다.","JPN":"ご勘弁を。あれはダンスというより、暴力に近いです。","ENG":"Please let it side. It is closer to violence than dancing.","TWN":"殿下就放過我吧。那個不算是跳舞，比較像是在施暴吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP"},{"id":"L22_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 시기가 시기다. 식량은 아끼고 최소한의 긴장감만큼은 유지해야 해.","JPN":"だが、このような時期だ。食糧を節約し、最低限の緊張感だけは保つべきだ。","ENG":"However, considering the circumstances, we must save resources and retain the least bit of tension.","TWN":"但此一時彼一時，現在必須節省糧食，稍微繃緊神經。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"무도회라면 전쟁이 끝난 뒤에 열어도 늦지 않겠지.","JPN":"舞踏会なら戦争が終わってからでも遅くない。","ENG":"The ball can be organized after the war.","TWN":"舞會可以等到戰爭結束後再舉辦也不遲。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"윽. 그건…","JPN":"うっ、それは……","ENG":"Ngh.","TWN":"呃，那個…"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"루크레시아. 왜 그래?","JPN":"ルクレシア。どうしたの？","ENG":"What's wrong, Lucrecia?","TWN":"露可蕾西亞，你有話要說嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"전하. 제 생각은 조금 다릅니다.","JPN":"殿下。私はそうは思いません。","ENG":"I have a different opinion, Your Highness.","TWN":"殿下，我的看法不同。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"무도회가 가지는 가장 큰 의의는 황족의 건재함을 드러내는 것.","JPN":"舞踏会が持つ最大の意義は、皇族が健在であると示すこと。","ENG":"The importance of a ball lies in the display of the royal family's prosperity.","TWN":"舞會最大的意義，在於向世人表達皇室的穩固。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"적의 군세가 사그라진 지금. 병사들의 사기를 올리는 데에 이만한 것이 어디 있겠습니까?","JPN":"敵の軍勢が弱まった今。兵士の士気を向上させるのに、これ以上のものはないでしょう。","ENG":"Now is the time, when the enemy's forces have subsided. What better way to raise the morale of the soldiers than with a ball?","TWN":"如今敵軍勢力衰退，還有什麼比舞會更能鼓舞士氣的呢？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"호오. 성녀님께서는 신민들이 낸 세금으로 사치라도 부리고 싶으신 건가?","JPN":"ほお。聖女様は、臣民の税金で贅沢でもしたいのか？","ENG":"Ho-oh. Does the Saintess wish to indulge in luxury with our subjects' taxes?","TWN":"喔？聖女此言是想要浪費百姓的納稅錢嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"기각이다. 제국을 수호하는 기사단이 놀음에 빠져 있을 수는 없어.","JPN":"却下だ。帝国を守護する騎士団が、遊興にふけっているわけにはいかない。","ENG":"Dismissed. The knights are supposed to protect the Empire, not dance and carouse the night away.","TWN":"駁回。守護帝國可不是小朋友扮家家酒。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"연회를 제안한 것은 전하가 아니십니까.","JPN":"宴を提案したのは殿下ではありませんか。","ENG":"I believe you were the one who suggested the banquet, Your Highness.","TWN":"但提出要慶功宴的人不正是殿下自己嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"예산 차원의 문제다.","JPN":"予算の問題だ。","ENG":"It is a budget issue.","TWN":"這是攸關國家財政的問題。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"사치향락을 즐기고 싶다면 네 천한 몸뚱어리로 다른 사제들이나 유혹해보도록.","JPN":"贅沢と享楽を楽しみたいのなら、貴様の低俗な体で他の司祭でも誘惑することだな。","ENG":"If you wish to indulge yourself in luxury and pleasure, I suggest you make use of that indecent body of yours to seduce the other priests.","TWN":"你想享樂的話，就用你那卑賤的身體去誘惑其他的祭司吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"뭣하면 저기 있는 평민이라도 말이다.","JPN":"何なら、あちらの平民はどうだ。","ENG":"Or that peasant over there, if you wish.","TWN":"再不然，那邊那個平民也可以。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"불경합니다, 전하! 구원자님은 그런 분이 아니에요!","JPN":"不敬です、殿下！　救世主様はそのような方ではありません！","ENG":"That's sacrilegious, Your Highness! The Savior is not that kind of person!","TWN":"殿下慎言！救贖者大人大人不是殿下可以拿來嘲弄的對象！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_01"},{"id":"L46_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"잘 알고 있군. 머리가 돌아간다면 적어도 그 천박한 입만큼은 함부로 놀리지 말도록.","JPN":"よくわかっているではないか。頭が回るのなら、少なくともその軽薄な口を閉じていることだな。","ENG":"Correct. It would be wise not to run your lowly mouth any further.","TWN":"你知道就好，那就管好你那張嘴。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"우린 마왕 토벌을 위해 모인 기사단이지. 방탕한 축제를 위한 놀음꾼이 아니야.","JPN":"我々は魔王討伐のために集まった騎士団だ。ふらちな祭りにうつつを抜かす遊び人ではない。","ENG":"We are knights gathered for the common goal of slaying the Demon Lord. Not some riff-raff who only seek pleasure.","TWN":"騎士團成立的目的是要討伐魔王，不是為醉酒享樂。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……그건.","JPN":"……それは。","ENG":"...That's.","TWN":"可是…"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_01"},{"id":"L1_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이 안건은 넘어가도록 하지. 달리 이견이 있는가?","JPN":"この案件はこれで終わりだ。異見はあるか？","ENG":"We shall move on from this subject. Or are there any objections?","TWN":"這件事就到此為止，還有其他討論事項嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"전하의 명에 따르겠습니다.","JPN":"殿下の仰せのままに。","ENG":"I concur, Your Highness.","TWN":"都聽殿下的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"…네, 저도 없습니다.","JPN":"……はい、僕もありません。","ENG":"...I do as well.","TWN":"…我也沒有。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"좋다. 오늘 회의는 끝이니 다들 푹 쉬도록.","JPN":"いいだろう。本日の会議はこれまでとする。皆、ゆっくりと休むように。","ENG":"Very well. That will be all for today's assembly. Go get some rest.","TWN":"好，那今天的會議就到這裡，大家去休息吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"내일부터는 고된 여정이 기다리고 있을 테니 말이다.","JPN":"明日からはきつい日程が待っているはずだからな。","ENG":"A trying journey awaits you tomorrow.","TWN":"明天還有辛苦的旅程在等著呢。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}}]`);export{e as default};